import{_ as a,o,c as t,a2 as s}from"./chunks/framework.7R1OEGYz.js";const u=JSON.parse('{"title":"Costs and limits","description":"","frontmatter":{},"headers":[],"relativePath":"developers/costs.md","filePath":"developers/costs.md"}'),r={name:"developers/costs.md"};function n(i,e,d,h,l,c){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="costs-and-limits" tabindex="-1">Costs and limits <a class="header-anchor" href="#costs-and-limits" aria-label="Permalink to &quot;Costs and limits&quot;">​</a></h1><p>Suho runs a relayer so users never need gas to start. This page says who pays for what, how the reimbursement model keeps that honest, and where the limits are.</p><h2 id="who-pays-for-what" tabindex="-1">Who pays for what <a class="header-anchor" href="#who-pays-for-what" aria-label="Permalink to &quot;Who pays for what&quot;">​</a></h2><ul><li><strong>Onboarding is sponsored.</strong> Creating an account is one relayer-paid transaction. The new account holds no ETH and signs nothing on chain itself. The relayer pays the gas and is not reimbursed. This is the only free operation.</li><li><strong>Everyday operations are reimbursed.</strong> A send, a card update, or a recovery can pay the relayer back out of the account&#39;s own balance, up to a cap the passkey signed. The relayer is made whole; the user pays their own gas from their own funds.</li><li><strong>The user is never overcharged.</strong> The cap (<code>maxGasPayment</code>) is part of the signed challenge, so a relayer cannot inflate the charge. The account pays the smaller of the real cost and the cap.</li></ul><h2 id="the-reimbursement-model" tabindex="-1">The reimbursement model <a class="header-anchor" href="#the-reimbursement-model" aria-label="Permalink to &quot;The reimbursement model&quot;">​</a></h2><p><code>OndolAccountV3.execute</code> measures the gas it used, adds a fixed overhead for the parts the meter cannot see, adds an upper-bound L1 fee from the OP-Stack gas oracle, and reimburses whoever paid the gas. It pays the smaller of that amount and the signed cap, and it biases slightly high within the cap so the relayer is never left short.</p><p>A cap of zero means sponsored: no reimbursement, exactly like V2. Onboarding uses this path.</p><p>The guardian recommends a cap before each signature. <code>GET /fee</code> returns a <code>maxGasPayment</code> of <code>(representative gas x gas price + L1 upper bound) x 1.25</code>, using the same oracle and transaction size the contract charges against, so the number the app shows and the passkey signs matches what the contract will take.</p><p>Before relaying, the guardian simulates the exact transaction with <code>eth_call</code>. If it would revert, the guardian refuses with a plain sentence and spends no gas.</p><h2 id="limits-on-sponsored-onboarding" tabindex="-1">Limits on sponsored onboarding <a class="header-anchor" href="#limits-on-sponsored-onboarding" aria-label="Permalink to &quot;Limits on sponsored onboarding&quot;">​</a></h2><p>Because onboarding is free, it is capped three ways:</p><ul><li><strong>Per IP:</strong> a rolling hourly limit per address.</li><li><strong>Global daily cap:</strong> <code>SUHO_ONBOARD_DAILY_CAP</code> (default 200) new accounts per UTC day.</li><li><strong>One passkey, one onboarding:</strong> the same public key cannot onboard twice.</li></ul><p>When the relayer balance falls below its floor (<code>SUHO_RELAYER_FLOOR_WEI</code>), sponsored onboarding pauses and the app shows &quot;New account creation is paused. The demo relayer needs a top-up.&quot; Reimbursed operations keep working. Nothing fails silently.</p><h2 id="the-relayer-and-how-to-check-it" tabindex="-1">The relayer, and how to check it <a class="header-anchor" href="#the-relayer-and-how-to-check-it" aria-label="Permalink to &quot;The relayer, and how to check it&quot;">​</a></h2><p>The demo relayer address is <a href="https://sepolia-explorer.giwa.io/address/0x8C2BD308Fc0E6A1F96bB81AE9bD53E9f793117D9" target="_blank" rel="noreferrer"><code>0x8C2BD308Fc0E6A1F96bB81AE9bD53E9f793117D9</code></a>. Anyone can top it up or audit its spend on the explorer.</p><p><code>GET /health</code> reports the live picture with no secrets: relayer address and balance, the floor and whether onboarding is paused, onboardings today against the cap, relays served, chain head and Flashblocks head, and the last error. It is public so you and the GIWA team can see the service is alive.</p>',16)])])}const m=a(r,[["render",n]]);export{u as __pageData,m as default};
